import{_ as l}from"./chunks/FetchSearch.vue_vue_type_script_setup_true_lang.CJ_CBJE8.js";import{T as t}from"./chunks/ZigenTrain.C7rShfGl.js";import{Z as o}from"./chunks/ZigenMap.De6Z-6SY.js";import{o as n,c as s,a2 as h,m as a,G as i,a as r}from"./chunks/framework.B85pf_eX.js";import"./chunks/share.Cqv2gPSS.js";import"./chunks/html2canvas-pro.esm.C7wW9koE.js";import"./chunks/advancedSchedule.CyVEQGBC.js";import"./chunks/cascadeStyles.CxvXO4ZZ.js";/* empty css                                                                          */const m={class:"zigen-font"},d={class:"zigen-font"},v=JSON.parse('{"title":"魔灵","description":"","frontmatter":{"aside":false},"headers":[],"relativePath":"ime/moling.md","filePath":"ime/moling.md"}'),c={name:"ime/moling.md"},A=Object.assign(c,{setup(f){return(p,e)=>(n(),s("div",null,[e[0]||(e[0]=h('<h1 id="魔灵" tabindex="-1">魔灵 <a class="header-anchor" href="#魔灵" aria-label="Permalink to &quot;魔灵&quot;">​</a></h1><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p><a href="https://github.com/Dieken/code_genie/tree/moling/moling#readme" target="_blank" rel="noreferrer">魔灵两可</a>输入方案，简称「魔灵」，结合了 90% 的<a href="https://shurufa.app/docs/ling.html" target="_blank" rel="noreferrer">灵明</a> 和 10% 的<a href="https://shurufa.app/docs/star.html" target="_blank" rel="noreferrer">星陈</a>的设计：</p><ol><li>参照灵明，使用 25 键方案，声母 z/zh 用 v 代替，零声母用 w 代替，另外声母 y 用 k 代替以降低 Y 键压力；</li><li>字根聚类程度接近灵明；</li><li>非成字字根和非常用字字根省略声码，字根韵码取字根首笔笔画，映射到 A(折)、 E(撇)、 U(竖)、I(点)、O(横)，不用记忆生僻字读音；</li><li>没有大小根和第三根跳根，常用字字根可以组二字词，打词体验类似传统四定，但因编码空间限制，也是定位主单辅词；</li><li>单字编码为 A1A2A3AzSzYz，除了双根字编码为 A1A2S2S1Y1 ，模仿了星陈的回头码设计，单字编码限长四码；</li></ol><p>魔灵两可的初衷是降低灵明的学习难度（灵明要记忆省略声母的小根），以及舍弃了灵明二码字根字不能组二字词的设计决策（灵明是为了码长短），虽然魔灵两可的简体动态重码率还不错，但在静态重码数、繁体动态重码率、当量、码长上都距灵明甚远，只能算是结合了灵明特性的改进版星陈（但繁体性能依然比星陈差），因此并不推荐使用，对自定码感兴趣的朋友应去学习宇浩输入法系列的日月和灵明方案。</p><p>使用<a href="https://ceping.shurufa.app" target="_blank" rel="noreferrer">宇浩测评</a>测得的性能指标：</p><ul><li>通用规范 8105 字静重： 358 非首选字；</li><li>常用国字 4808 字静重： 119 非首选字；</li><li>知乎简体·频率降序动重： 1.26‱；</li><li>北语简体·频率降序动重： 1.95‱；</li><li>台标繁体·频率降序动重： 37.18‱；</li><li>知乎简体字频全码当量： 1.2829；</li><li>北语简体字频全码当量： 1.2857；</li><li>台标繁体字频全码当量： 1.3131；</li><li>简码效率： 北语字频 50 简码 3.108，100 简码 2.978，所有简码 2.752；</li></ul><h2 id="致谢" tabindex="-1">致谢 <a class="header-anchor" href="#致谢" aria-label="Permalink to &quot;致谢&quot;">​</a></h2><ul><li>感谢朱宇浩制作的优质拆分和灵明、星陈优质方案；</li><li>感谢 @荒 的<a href="https://github.com/hertz-hwang/code_genie" target="_blank" rel="noreferrer">码灵</a>优化程序；</li><li>感谢上述两位作者的讨论和指导，以及群友 @Litles 的多次启发，尤其是提出了取字根首笔笔画代替韵母的设计；</li></ul><h2 id="拆分" tabindex="-1">拆分 <a class="header-anchor" href="#拆分" aria-label="Permalink to &quot;拆分&quot;">​</a></h2>',10)),a("div",m,[i(l,{chaifenUrl:"/chaifen.json",zigenUrl:"/zigen-moling.csv",rule:"moling"})]),e[1]||(e[1]=a("h2",{id:"字根",tabindex:"-1"},[r("字根 "),a("a",{class:"header-anchor",href:"#字根","aria-label":'Permalink to "字根"'},"​")],-1)),i(o,{"default-scheme":"moling",chaifenUrl:"/chaifen.json","column-min-width":"1rem",schemeCnName:"魔灵",customFooter:"QQ群: 544760766 · 本图链接: https://shurufa.app/ime/moling"}),e[2]||(e[2]=a("h2",{id:"练习",tabindex:"-1"},[r("练习 "),a("a",{class:"header-anchor",href:"#练习","aria-label":'Permalink to "练习"'},"​")],-1)),a("div",d,[i(t,{name:"moling",chaifenUrl:"/chaifen.json",zigenUrl:"/zigen-moling.csv",range:[0],mode:"both",rule:"moling"})])]))}});export{v as __pageData,A as default};
